_init_db()

def _read_upload_limited(upload: UploadFile, max_bytes: int) -> bytes:
    data = upload.file.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise HTTPException(status_code=413, detail=f"Upload too large (>{max_bytes} bytes)")
    return data

def _normalize_label(label: str) -> str:
    if label is None:
        return ""
    label = str(label).strip()
    label = label.replace("\n", " ").replace("\r", " ").strip()
    return label

def _is_image_filename(name: str) -> bool:
    ext = os.path.splitext(name.lower())[1]
    return ext in [".jpg", ".jpeg", ".png", ".bmp", ".gif", ".webp"]

def _load_image_bytes_to_rgb(image_bytes: bytes, image_size: int) -> Tuple[np.ndarray, int, int]:
    with Image.open(io.BytesIO(image_bytes)) as im:
        im = im.convert("RGB")
        w, h = im.size
        im = im.resize((image_size, image_size), resample=Image.BILINEAR)
        arr = np.asarray(im, dtype=np.uint8)
    return arr, w, h

def _save_image_array(arr: np.ndarray, out_path: str) -> None:
    im = Image.fromarray(arr.astype(np.uint8), mode="RGB")
    _safe_mkdir(os.path.dirname(out_path))
    im.save(out_path, format="JPEG", quality=92, optimize=True)

def _dataset_image_path(label: str, image_sha256: str) -> str:
    safe_label = "".join([c if c.isalnum() or c in ("-", "_") else "_" for c in label])[:128] or "unknown"
    subdir = os.path.join(DATASET_DIR, "images", safe_label)
    return os.path.join(subdir, f"{image_sha256}.jpg")

def _insert_contribution(conn: sqlite3.Connection, **kwargs) -> None:
    cols = ",".join(kwargs.keys())
    qs = ",".join(["?"] * len(kwargs))
    conn.execute(f"INSERT INTO contributions ({cols}) VALUES ({qs})", list(kwargs.values()))

def _update_contribution(conn: sqlite3.Connection, cid: str, **kwargs) -> None:
    sets = ",".join([f"{k}=?" for k in kwargs.keys()])
    conn.execute(f"UPDATE contributions SET {sets} WHERE id=?", list(kwargs.values()) + [cid])

def _insert_example(conn: sqlite3.Connection, **kwargs) -> None:
    cols = ",".join(kwargs.keys())
    qs = ",".join(["?"] * len(kwargs))
    conn.execute(f"INSERT INTO examples ({cols}) VALUES ({qs})", list(kwargs.values()))

def _count_examples(conn: sqlite3.Connection) -> int:
    row = conn.execute("SELECT COUNT(*) AS c FROM examples").fetchone()
    return int(row["c"])

def _get_label_counts(conn: sqlite3.Connection) -> Dict[str, int]:
    rows = conn.execute("SELECT label, COUNT(*) AS c FROM examples GROUP BY label").fetchall()
    return {r["label"]: int(r["c"]) for r in rows}

def _get_examples_df(conn: sqlite3.Connection) -> pd.DataFrame:
    rows = conn.execute("SELECT image_path, label FROM examples").fetchall()
    if not rows:
        return pd.DataFrame(columns=["image_path", "label"])
    return pd.DataFrame([{"image_path": r["image_path"], "label": r["label"]} for r in rows])

def _split_df(df: pd.DataFrame, val_split: float, test_split: float, seed: int = 1337) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if df.empty:
        return df, df, df
    df = df.sample(frac=1.0, random_state=seed).reset_index(drop=True)
    n = len(df)
    n_test = int(round(n * test_split))
    n_val = int(round(n * val_split))
    n_test = min(n_test, n)
    n_val = min(n_val, n - n_test)
    test_df = df.iloc[:n_test].reset_index(drop=True)
    val_df = df.iloc[n_test:n_test + n_val].reset_index(drop=True)
    train_df = df.iloc[n_test + n_val:].reset_index(drop=True)
    return train_df, val_df, test_df

def _build_model(num_classes: int, image_size: int, learning_rate: float) -> tf.keras.Model:
    base = tf.keras.applications.MobileNetV2(
        input_shape=(image_size, image_size, 3),
        include_top=False,
        weights="imagenet"
    )
    base.trainable = False
    inputs = tf.keras.Input(shape=(image_size, image_size, 3), name="image")
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs)
    x = base(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax", name="pred")(x)
    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=learning_rate),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model

def _make_tf_dataset(df: pd.DataFrame, label_to_id: Dict[str, int], image_size: int, batch_size: int, training: bool) -> tf.data.Dataset:
    paths = df["image_path"].astype(str).tolist()
    labels = [label_to_id[lbl] for lbl in df["label"].astype(str).tolist()]

    ds = tf.data.Dataset.from_tensor_slices((paths, labels))

    def _load(path, label):
        img = tf.io.read_file(path)
        img = tf.image.decode_jpeg(img, channels=3)
        img = tf.image.resize(img, [image_size, image_size], method="bilinear")
        img = tf.cast(img, tf.float32)
        return img, label

    ds = ds.map(_load, num_parallel_calls=tf.data.AUTOTUNE)
    if training:
        ds = ds.shuffle(min(len(paths), 4096), reshuffle_each_iteration=True)
        ds = ds.map(lambda x, y: (tf.image.random_flip_left_right(x), y), num_parallel_calls=tf.data.AUTOTUNE)
    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds

def _export_active_model(model: tf.keras.Model, labels: List[str], metrics: Dict[str, Any], run_dir: str) -> None:
    tmp_dir = os.path.join(run_dir, "export")
    _safe_mkdir(tmp_dir)
    model.save(tmp_dir, include_optimizer=False)
    with open(os.path.join(tmp_dir, "labels.json"), "w", encoding="utf-8") as f:
        json.dump(labels, f, ensure_ascii=False, indent=2)
    with open(os.path.join(tmp_dir, "metrics.json"), "w", encoding="utf-8") as f:
        json.dump(metrics, f, ensure_ascii=False, indent=2)
    if os.path.exists(ACTIVE_MODEL_DIR):
        shutil.rmtree(ACTIVE_MODEL_DIR, ignore_errors=True)
    shutil.copytree(tmp_dir, ACTIVE_MODEL_DIR)

def _load_active_model() -> Tuple[Optional[tf.keras.Model], Optional[List[str]]]:
    model_path = ACTIVE_MODEL_DIR
    labels_path = os.path.join(ACTIVE_MODEL_DIR, "labels.json")
    if not os.path.isdir(model_path) or not os.path.exists(labels_path):
        return None, None
    try:
        model = tf.keras.models.load_model(model_path)
        with open(labels_path, "r", encoding="utf-8") as f:
            labels = json.load(f)
        if not isinstance(labels, list):
            return model, None
        return model, labels
    except Exception:
        return None, None

class TrainRequest(BaseModel):
    image_size: int = DEFAULT_IMAGE_SIZE
    batch_size: int = DEFAULT_BATCH_SIZE
    epochs: int = DEFAULT_EPOCHS
