@app.post("/upload/csv")
async def upload_csv(
    file: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
    image_size: int = Form(DEFAULT_IMAGE_SIZE),
    label_column: str = Form("label"),
    image_path_column: str = Form("image_path"),
    image_bytes_column: Optional[str] = Form(None),
    base_dir: Optional[str] = Form(None),
):
    if not file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="Expected a .csv file")

    raw = _read_upload_limited(file, DEFAULT_MAX_UPLOAD_BYTES)
    cid = str(uuid.uuid4())
    sha = _sha256_bytes(raw)
    up_dir = os.path.join(UPLOADS_DIR, cid)
    _safe_mkdir(up_dir)
    csv_path = os.path.join(up_dir, "data.csv")
    with open(csv_path, "wb") as f:
        f.write(raw)

    conn = _db()
    try:
        _insert_contribution(
            conn,
            id=cid,
            created_at=_utcnow(),
            contributor_id=contributor_id,
            source_type="csv",
            original_filename=file.filename,
            sha256=sha,
            bytes=len(raw),
            status="processing",
            message=None,
            num_rows=None,
            num_images=None,
            num_labels=None
        )
        conn.commit()

        df = pd.read_csv(csv_path)
        if label_column not in df.columns:
            raise HTTPException(status_code=400, detail=f"Missing label column '{label_column}'")
        if image_path_column not in df.columns and (not image_bytes_column or image_bytes_column not in df.columns):
            raise HTTPException(status_code=400, detail=f"CSV must include '{image_path_column}' or '{image_bytes_column}'")

        num_rows = len(df)
        num_images = 0
        labels_set = set()

        for idx, row in df.iterrows():
            label = _normalize_label(row.get(label_column))
            if not label:
                continue

            img_bytes = None
            if image_bytes_column and image_bytes_column in df.columns and pd.notna(row.get(image_bytes_column)):
                val = row.get(image_bytes_column)
                if isinstance(val, str):
                    try:
                        img_bytes = bytes.fromhex(val)
                    except Exception:
                        img_bytes = None
            if img_bytes is None:
                rel = row.get(image_path_column) if image_path_column in df.columns else None
                if rel is None or (isinstance(rel, float) and np.isnan(rel)):
                    continue
                rel = str(rel)
                if base_dir:
                    img_path = os.path.join(base_dir, rel)
                else:
                    img_path = rel
                if not os.path.isfile(img_path):
                    continue
                with open(img_path, "rb") as f:
                    img_bytes = f.read()

            try:
                arr, w, h = _load_image_bytes_to_rgb(img_bytes, image_size)
            except Exception:
                continue

            img_sha = _sha256_bytes(img_bytes)
            out_path = _dataset_image_path(label, img_sha)
            if not os.path.exists(out_path):
                _save_image_array(arr, out_path)

            ex_id = str(uuid.uuid4())
            _insert_example(
                conn,
                id=ex_id,
                created_at=_utcnow(),
                contribution_id=cid,
                label=label,
                image_path=out_path,
                image_sha256=img_sha,
                width=w,
                height=h
            )
            num_images += 1
            labels_set.add(label)

        _update_contribution(
            conn,
            cid,
            status="ready",
            message=None,
            num_rows=num_rows,
            num_images=num_images,
            num_labels=len(labels_set)
        )
        conn.commit()

        return {
            "contribution_id": cid,
            "status": "ready",
            "num_rows": num_rows,
            "num_images_added": num_images,
            "num_labels": len(labels_set)
        }
    except HTTPException:
        _update_contribution(conn, cid, status="error", message="Invalid CSV or data")
        conn.commit()
        raise
    except Exception as e:
        _update_contribution(conn, cid, status="error", message=str(e)[:500])
        conn.commit()
        raise HTTPException(status_code=500, detail="Server error while processing CSV")
    finally:
        conn.close()

@app.post("/upload/zip")
async def upload_zip(
    file: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
    image_size: int = Form(DEFAULT_IMAGE_SIZE),
    csv_name: str = Form("labels.csv"),
    label_column: str = Form("label"),
    image_path_column: str = Form("image_path"),
):
    if not file.filename.lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="Expected a .zip file")

    raw = _read_upload_limited(file, DEFAULT_MAX_UPLOAD_BYTES)
    cid = str(uuid.uuid4())
    sha = _sha256_bytes(raw)
    up_dir = os.path.join(UPLOADS_DIR, cid)
    _safe_mkdir(up_dir)
    zip_path = os.path.join(up_dir, "upload.zip")
    with open(zip_path, "wb") as f:
        f.write(raw)

    conn = _db()
    try:
        _insert_contribution(
            conn,
            id=cid,
            created_at=_utcnow(),
            contributor_id=contributor_id,
            source_type="zip",
            original_filename=file.filename,
            sha256=sha,
            bytes=len(raw),
            status="processing",
            message=None,
            num_rows=None,
            num_images=None,
            num_labels=None
        )
        conn.commit()

        extract_dir = os.path.join(up_dir, "extracted")
        _safe_mkdir(extract_dir)
        with zipfile.ZipFile(zip_path, "r") as z:
            z.extractall(extract_dir)

        csv_path = os.path.join(extract_dir, csv_name)
        if not os.path.isfile(csv_path):
            raise HTTPException(status_code=400, detail=f"Missing {csv_name} in zip")

        df = pd.read_csv(csv_path)
        if label_column not in df.columns or image_path_column not in df.columns:
            raise HTTPException(status_code=400, detail=f"CSV must include '{label_column}' and '{image_path_column}'")

        num_rows = len(df)
        num_images = 0
        labels_set = set()

        for _, row in df.iterrows():
            label = _normalize_label(row.get(label_column))
            if not label:
                continue
            rel = row.get(image_path_column)
            if rel is None or (isinstance(rel, float) and np.isnan(rel)):
                continue
            rel = str(rel)
            img_path = os.path.join(extract_dir, rel)
            if not os.path.isfile(img_path) or not _is_image_filename(img_path):
                continue
            with open(img_path, "rb") as f:
                img_bytes = f.read()
            try:
                arr, w, h = _load_image_bytes_to_rgb(img_bytes, image_size)
            except Exception:
                continue

            img_sha = _sha256_bytes(img_bytes)
            out_path = _dataset_image_path(label, img_sha)
            if not os.path.exists(out_path):
                _save_image_array(arr, out_path)

            ex_id = str(uuid.uuid4())
            _insert_example(
                conn,
                id=ex_id,
                created_at=_utcnow(),
                contribution_id=cid,
                label=label,
                image_path=out_path,
                image_sha256=img_sha,
                width=w,
                height=h
            )
            num_images += 1
            labels_set.add(label)

        _update_contribution(
            conn,
            cid,
            status="ready",
            message=None,
            num_rows=num_rows,
            num_images=num_images,
            num_labels=len(labels_set)
        )
        conn.commit()

        return {
            "contribution_id": cid,
            "status": "ready",
            "num_rows": num_rows,
            "num_images_added": num_images,
            "num_labels": len(labels_set)
        }
    except HTTPException:
        _update_contribution(conn, cid, status="error", message="Invalid ZIP or data")
        conn.commit()
        raise
    except Exception as e:
        _update_contribution(conn, cid, status="error", message=str(e)[:500])
        conn.commit()
        raise HTTPException(status_code=500, detail="Server error while processing ZIP")
    finally:
        conn.close()

def _train_job(train_id: str, req: TrainRequest) -> None:
    with TRAIN_LOCK:
        conn = _db()
        try:
            conn.execute("UPDATE trainings SET status=?, message=? WHERE id=?", ("running", None, train_id))
            conn.commit()

            df = _get_examples_df(conn)
            if df.empty:
                conn.execute("UPDATE trainings SET status=?, message=? WHERE id=?", ("error", "No training examples available", train_id))
                conn.commit()
                return

            label_counts = df["label"].value_counts().to_dict()
            eligible_labels = [lbl for lbl, c in label_counts.items() if int(c) >= req.min_examples_per_class]
            eligible_labels = sorted(eligible_labels)[:req.max_classes]
            df = df[df["label"].isin(eligible_labels)].reset_index(drop=True)

            if df.empty or len(eligible_labels) < 2:
                conn.execute("UPDATE trainings SET status=?, message=? WHERE id=?", ("error", "Not enough data/classes to train", train_id))
                conn.commit()
                return

            labels = sorted(df["label"].unique().tolist())
            label_to_id = {l: i for i, l in enumerate(labels)}

            train_df, val_df, test_df = _split_df(df, req.val_split, req.test_split)
            if train_df.empty or val_df.empty:
                conn.execute("UPDATE trainings SET status=?, message=? WHERE id=?", ("error", "Train/val split resulted in empty set", train_id))
                conn.commit()
                return

            train_ds = _make_tf_dataset(train_df, label_to_id, req.image_size, req.batch_size, training=True)
            val_ds = _make_tf_dataset(val_df, label_to_id, req.image_size, req.batch_size, training=False)

            run_dir = os.path.join(TRAIN_RUNS_DIR, train_id)
            _safe_mkdir(run_dir)

            model = _build_model(num_classes=len(labels), image_size=req.image_size, learning_rate=req.learning_rate)

            callbacks = [
                tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=3, restore_best_weights=True),
                tf.keras.callbacks.ModelCheckpoint(filepath=os.path.join(run_dir, "best.keras"), monitor="val_accuracy", save_best_only=True),
                tf.keras.callbacks.CSVLogger(os.path.join(run_dir, "history.csv"))
            ]

            history = model.fit(train_ds, validation_data=val_ds, epochs=req.epochs, callbacks=callbacks, verbose=0)

            if req.fine_tune:
                base = None
                for layer in model.layers:
                    if isinstance(layer, tf.keras.Model) and layer.name.startswith("mobilenetv2"):
                        base = layer
                        break
                if base is None:
                    base = model.layers[2] if len(model.layers) > 2 else None
                if hasattr(base, "layers"):
                    base.trainable = True
                    fine_tune_at = max(0, min(req.fine_tune_at, len(base.layers)))
                    for l in base.layers[:fine_tune_at]:
                        l.trainable = False
                    model.compile(
                        optimizer=tf.keras.optimizers.Adam(learning_rate=req.learning_rate * 0.1),
                        loss="sparse_categorical_crossentropy",
                        metrics=["accuracy"]
                    )
                    model.fit(train_ds, validation_data=val_ds, epochs=max(1, req.epochs // 2), callbacks=callbacks, verbose=0)

            metrics = {}
            try:
                val_loss, val_acc = model.evaluate(val_ds, verbose=0)
                metrics["val_loss"] = float(val_loss)
                metrics["val_accuracy"] = float(val_acc)
            except Exception:
                pass

            if not test_df.empty:
                try:
                    test_ds = _make_tf_dataset(test_df, label_to_id, req.image_size, req.batch_size, training=False)
                    test_loss, test_acc = model.evaluate(test_ds, verbose=0)
                    metrics["test_loss"] = float(test_loss)
                    metrics["test_accuracy"] = float(test_acc)
                except Exception:
                    pass

            metrics["num_examples"] = int(len(df))
            metrics["num_classes"] = int(len(labels))
            metrics["trained_at"] = _utcnow()

            _export_active_model(model, labels, metrics, run_dir)

            model_id = str(uuid.uuid4())
            conn.execute(
                "INSERT INTO models (id, created_at, status, message, model_dir, metrics_json, num_classes, labels_json) VALUES (?,?,?,?,?,?,?,?)",
                (model_id, _utcnow(), "active", None, ACTIVE_MODEL_DIR, json.dumps(metrics), len(labels), json.dumps(labels))
            )
            conn.execute(
                "UPDATE trainings SET status=?, message=?, metrics_json=?, model_dir=?, num_examples=?, num_classes=? WHERE id=?",
                ("completed", None, json.dumps(metrics), run_dir, int(len(df)), int(len(labels)), train_id)
            )
            conn.commit()
        except Exception as e:
            try:
                conn.execute("UPDATE trainings SET status=?, message=? WHERE id=?", ("error", str(e)[:500], train_id))
                conn.commit()
            except Exception:
                pass
        finally:
            conn.close()

@app.post("/train")
def train(req: TrainRequest, background: BackgroundTasks):
    train_id = str(uuid.uuid4())
    conn = _db()
    try:
        conn.execute(
            "INSERT INTO trainings (id, created_at, status, message, params_json, metrics_json, model_dir, num_examples, num_classes) VALUES (?,?,?,?,?,?,?,?,?)",
            (train_id, _utcnow(), "queued", None, req.model_dump_json(), None, None, None, None)
        )
        conn.commit()
    finally:
        conn.close()

    background.add_task(_train_job, train_id, req)
    return {"training_id": train_id, "status": "queued"}

@app.get("/train/{training_id}")
def train_status(training_id: str):
    conn = _db()
    try:
        row = conn.execute("SELECT * FROM trainings WHERE id=?", (training_id,)).fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="Training not found")
        out = dict(row)
        if out.get("params_json"):
            out["params"] = json.loads(out["params_json"])
        if out.get("metrics_json"):
            out["metrics"] = json.loads(out["metrics_json"])
        out.pop("params_json", None)
        out.pop("metrics_json", None)
        return out
    finally:
        conn.close()

@app.post("/predict", response_model=PredictResponse)
async def predict(file: UploadFile = File(...), top_k: int = Form(5), image_size: int = Form(DEFAULT_IMAGE_SIZE)):
    model, labels = _load_active_model()
    if model is None or not labels:
        raise HTTPException(status_code=400, detail="No active model available. Train a model first.")

    raw = _read_upload_limited(file, 20 * 1024 * 1024)
    try:
        arr, _, _ = _load_image_bytes_to_rgb(raw, image_size)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    x = np.expand_dims(arr.astype(np.float32), axis=0)
    preds = model.predict(x, verbose=0)[0]
    k = int(max(1, min(top_k, len(labels))))
    idxs = np.argsort(preds)[::-1][:k]
    top = [{"label": labels[int(i)], "confidence": float(preds[int(i)])} for i in idxs]
    best = top[0]
    return PredictResponse(label=best["label"], confidence=best["confidence"], top_k=top)

@app.get("/contributions")
def list_contributions(limit: int = 50, offset: int = 0):
    limit = int(max(1, min(limit, 500)))
    offset = int(max(0, offset))
    conn = _db()
    try:
        rows = conn.execute(
            "SELECT * FROM contributions ORDER BY created_at DESC LIMIT ? OFFSET ?",
            (limit, offset)
        ).fetchall()
        return {"items": [dict(r) for r in rows], "limit": limit, "offset": offset}
    finally:
        conn.close()

@app.get("/models")
def list_models(limit: int = 20, offset: int = 0):
    limit = int(max(1, min(limit, 200)))
    offset = int(max(0, offset))
    conn = _db()
    try:
        rows = conn.execute(
            "SELECT * FROM models ORDER BY created_at DESC LIMIT ? OFFSET ?",
            (limit, offset)
        ).fetchall()
        items = []
        for r in rows:
            d = dict(r)
            if d.get("metrics_json"):
                d["metrics"] = json.loads(d["metrics_json"])
            if d.get("labels_json"):
                d["labels"] = json.loads(d["labels_json"])
            d.pop("metrics_json", None)
            d.pop("labels_json", None)
            items.append(d)
        return {"items": items, "limit": limit, "offset": offset}
    finally:
        conn.close()

